<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Sorting Visualizer</title>
<style>
  * { box-sizing: border-box; }
  body {
    margin: 0;
    min-height: 100vh;
    background: #0d1117;
    color: #e6edf3;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 24px;
  }
  h1 {
    font-size: 20px;
    font-weight: 600;
    margin: 0 0 16px;
    letter-spacing: 0.5px;
  }
  #controls {
    display: flex;
    gap: 12px;
    margin-bottom: 20px;
    flex-wrap: wrap;
    justify-content: center;
  }
  button {
    background: #21262d;
    color: #e6edf3;
    border: 1px solid #30363d;
    border-radius: 6px;
    padding: 10px 18px;
    font-size: 14px;
    cursor: pointer;
    transition: background 0.15s, border-color 0.15s, transform 0.05s;
  }
  button:hover { background: #30363d; border-color: #8b949e; }
  button:active { transform: translateY(1px); }
  button:disabled { opacity: 0.5; cursor: not-allowed; }
  #sort { background: #238636; border-color: #238636; }
  #sort:hover { background: #2ea043; border-color: #2ea043; }
  #shuffle { background: #1f6feb; border-color: #1f6feb; }
  #shuffle:hover { background: #388bfd; border-color: #388bfd; }
  #bars {
    width: 100%;
    max-width: 900px;
    height: 60vh;
    min-height: 300px;
    display: flex;
    align-items: flex-end;
    gap: 2px;
    background: #161b22;
    border: 1px solid #30363d;
    border-radius: 8px;
    padding: 12px;
    overflow: hidden;
  }
  .bar {
    flex: 1 1 0;
    background: #58a6ff;
    border-radius: 3px 3px 0 0;
    transition: height 0.12s ease, background 0.12s ease;
    min-height: 2px;
  }
  .bar.compare { background: #f0883e; }
  .bar.swap { background: #f85149; }
  .bar.sorted { background: #3fb950; }
  #status {
    margin-top: 14px;
    font-size: 13px;
    color: #8b949e;
    min-height: 18px;
  }
</style>
</head>
<body>
  <h1>Sorting Algorithm Visualizer</h1>
  <div id="controls">
    <button id="sort">Sort</button>
    <button id="shuffle">Shuffle</button>
    <button id="reset">Reset</button>
  </div>
  <div id="bars"></div>
  <div id="status"></div>

<script>
(function () {
  const barsEl = document.getElementById('bars');
  const statusEl = document.getElementById('status');
  const sortBtn = document.getElementById('sort');
  const shuffleBtn = document.getElementById('shuffle');
  const resetBtn = document.getElementById('reset');

  const DEFAULT_SIZE = 40;
  let arr = [];
  let i = 0;       // pass index
  let j = 0;       // comparison index within a pass
  let finished = false;
  let animating = false;
  let lastCompare = -1, lastSwap = -1;

  function setStatus(msg) { statusEl.textContent = msg; }

  function genRandom(n) {
    const a = [];
    for (let k = 0; k < n; k++) a.push(Math.floor(Math.random() * 100) + 5);
    return a;
  }

  function render() {
    barsEl.innerHTML = '';
    const max = Math.max.apply(null, arr.concat([1]));
    for (let k = 0; k < arr.length; k++) {
      const bar = document.createElement('div');
      bar.className = 'bar';
      bar.style.height = ((arr[k] / max) * 100) + '%';
      barsEl.appendChild(bar);
    }
  }

  function updateBar(k) {
    const bar = barsEl.children[k];
    if (!bar) return;
    const max = Math.max.apply(null, arr.concat([1]));
    bar.style.height = ((arr[k] / max) * 100) + '%';
  }

  function highlight() {
    for (let k = 0; k < barsEl.children.length; k++) {
      const b = barsEl.children[k];
      b.classList.remove('compare', 'swap', 'sorted');
      if (finished) {
        b.classList.add('sorted');
      } else if (k === lastSwap) {
        b.classList.add('swap');
      } else if (k === lastCompare || k === lastCompare + 1) {
        b.classList.add('compare');
      }
    }
  }

  function resetState() {
    i = 0;
    j = 0;
    finished = false;
    lastCompare = -1;
    lastSwap = -1;
  }

  function setArray(a) {
    arr = a.slice();
    resetState();
    render();
    highlight();
    setStatus('Array set (' + arr.length + ' elements).');
  }

  function array() { return arr.slice(); }

  function sorted() {
    for (let k = 0; k < arr.length - 1; k++) {
      if (arr[k] > arr[k + 1]) return false;
    }
    return true;
  }

  // Bubble sort, one comparison (and possible swap) per step.
  function sortStep() {
    if (finished) return true;
    const n = arr.length;
    if (n < 2) { finished = true; lastCompare = -1; lastSwap = -1; highlight(); return true; }

    // Perform one comparison step.
    lastCompare = j;
    if (arr[j] > arr[j + 1]) {
      const tmp = arr[j];
      arr[j] = arr[j + 1];
      arr[j + 1] = tmp;
      lastSwap = j;
      updateBar(j);
      updateBar(j + 1);
    } else {
      lastSwap = -1;
    }

    // Advance indices.
    j++;
    if (j >= n - 1 - i) {
      i++;
      j = 0;
      if (i >= n - 1) {
        finished = true;
        lastCompare = -1;
        lastSwap = -1;
        highlight();
        return true;
      }
    }
    highlight();
    return false;
  }

  function animateSort() {
    if (animating) return;
    animating = true;
    sortBtn.disabled = true;
    const speed = 30;
    function tick() {
      if (!animating) { sortBtn.disabled = false; return; }
      const done = sortStep();
      if (done) {
        animating = false;
        sortBtn.disabled = false;
        setStatus('Sorted!');
        highlight();
        return;
      }
      setTimeout(tick, speed);
    }
    tick();
  }

  function shuffle() {
    animating = false;
    sortBtn.disabled = false;
    const a = genRandom(DEFAULT_SIZE);
    // Fisher-Yates shuffle to ensure unsorted.
    for (let k = a.length - 1; k > 0; k--) {
      const r = Math.floor(Math.random() * (k + 1));
      const tmp = a[k]; a[k] = a[r]; a[r] = tmp;
    }
    setArray(a);
    setStatus('Shuffled.');
  }

  function reset() {
    animating = false;
    sortBtn.disabled = false;
    setArray(genRandom(DEFAULT_SIZE));
    setStatus('Reset.');
  }

  sortBtn.addEventListener('click', animateSort);
  shuffleBtn.addEventListener('click', shuffle);
  resetBtn.addEventListener('click', reset);

  // Initialize.
  setArray(genRandom(DEFAULT_SIZE));

  // Expose required API.
  window.viz = {
    array: array,
    setArray: setArray,
    sortStep: sortStep,
    sorted: sorted
  };
})();
</script>
</body>
</html>
